fun solve(value: Array<Long>, limit: Array<Long>): Long {
    val n = value.size
    val elements = Array(n) { i -> Pair(limit[i], value[i]) }
    elements.sortBy { it.first }

    var total = 0L
    var active = 0L
    var i = 0
    while (i < n) {
        val (currentLimit, currentValue) = elements[i]
        if (active < currentLimit) {
            total += currentValue
            active += 1
            i += 1
        } else {
            // Skip all elements with limit <= active
            while (i < n && elements[i].first <= active) {
                i += 1
            }
        }
    }
    return total
}
